class WordDictionary {
  constructor() { this.trie = {}; }
  addWord(word) { let node=this.trie; for(let c of word){ if(!node[c]) node[c]={}; node=node[c]; } node.isEnd=true; }
  search(word) { const dfs = (node, i) => { if(i===word.length) return !!node.isEnd; let c=word[i]; if(c==='.') { for(let k in node) { if(k!=='isEnd' && dfs(node[k], i+1)) return true; } return false; } else { if(!node[c]) return false; return dfs(node[c], i+1); } }; return dfs(this.trie, 0); }
}

